import React, { useState, useEffect } from "react";
import { OutlinedInput, InputLabel, MenuItem, Select, FormControl, Container } from "@mui/material";
import axios from "axios";



export default function Shape({onChange,value}) {
  const [selectedNames, setSelectedNames] = useState(value);
  const [choices, setchoices] = useState([])


  useEffect(()=>{
    axios({url:"https://app.liliumpharma.com/concurents/shapes/api/"})
    .then(res=>setchoices(res.data))
    .catch(err=>console.log(err))
  },[])



  useEffect(() => {
    onChange("shape",selectedNames );
  }, [selectedNames])
  

  



  return (
    <>
        <FormControl sx={{width:"100%", mb:1 }}>
        <InputLabel> Shape </InputLabel>
        <Select
            onChange={(e) => setSelectedNames(e.target.value)}
            value={selectedNames}
            input={<OutlinedInput label="Multiple Select"  fullWidth/>}
            fullWidth
        >   
        {choices.map(c=>
            <MenuItem value={c.id} key={c.id}> {c.name} </MenuItem>
            )}
        </Select>
        </FormControl>
    </>
  );
}