import React, { useState, useEffect } from "react";
import { OutlinedInput, InputLabel, MenuItem, Select, FormControl, Container } from "@mui/material";



export default function ProductSelector({onChange, products}) {
  const [selectedNames, setSelectedNames] = useState(products[0].id);



  useEffect(() => {
    onChange( products.filter(p=>p.id==selectedNames)[0]);
  }, [selectedNames])
  

  return (
    <Container>
        <FormControl sx={{mt:3, width:"100%", mb:1 }}>
        <InputLabel> Produit </InputLabel>
        <Select
            onChange={(e) => setSelectedNames(e.target.value)}
            value={selectedNames}
            input={<OutlinedInput label="Multiple Select"  fullWidth/>}
            fullWidth
        >
            {products.map((p) => (
            <MenuItem key={p.id} value={p.id}>
                {p.fname}
            </MenuItem>
            ))}
        </Select>
        </FormControl>
    </Container>
  );
}