import React from 'react'
import SingleCProduct from './SingleCProduct'
import { Container, Box, Typography } from '@mui/material'

export default function List({cproducts, open, setopen, setcproduct}) {
  return (
    <> 
    <Box sx={{textAlign:"center",my:2}}> 
        <Typography variant='title' ><b>Liste des concurrents <span className='text-primary'>({cproducts.length})</span> </b></Typography>
    </Box>
    <Container sx={{mt:2,mb:10}}>
      <Box sx={{display:"flex", overflowX:"scroll",alignItems:"stretch",gap:"10px",position:"relative",my:1}}>
          {cproducts.map(p=>
                  <SingleCProduct product={p} open={open} setopen={setopen} setcproduct={setcproduct} />
              )}
      </Box>  
    </Container>
    </>
  )
}
