import { Box, IconButton, Stack, TextField, Typography } from '@mui/material'
import React from 'react'
import ControlPointIcon from '@mui/icons-material/ControlPoint';
import DeleteIcon from '@mui/icons-material/Delete';


export default function Components({product, setproduct}) {

  return (
    <>  
        <Typography variant="h6" component="h2" my={1} >Composants </Typography>
        {product.components.map((p,index)=>
            <SingleForm  name={p.name}  qtt={p.qtt} index={index} product={product} setproduct={setproduct}/>
            )}
        <Box textAlign={"right"}>
            <IconButton color="primary"  onClick={()=>{setproduct({...product, components:[...product.components, {name:"", qtt:""}]})}}>
                <ControlPointIcon />
            </IconButton>
        </Box>    
    </>
  )
}

const SingleForm=({name, qtt, index, setproduct, product})=>{
    return(
        <Stack direction="row" mb={1} gap={1}>
            <TextField 
                name="name"
                label="name"
                onChange={(e)=>setproduct({...product,components:product.components.map((p,i)=> i==index ? {...p,name:e.target.value}: p)})}
                size='small'
                defaultValue={name}
            />
            <TextField 
                name="qtt"
                label="qtt"
                onChange={(e)=>setproduct({...product,components:product.components.map((p,i)=> i==index ? {...p,qtt:e.target.value}: p)})}
                size='small'
                defaultValue={qtt}
            />
            <IconButton color="#00ffff"  onClick={()=>{setproduct({...product, components:product.components.filter((c,i)=>i!=index)})}}>
                <DeleteIcon />
            </IconButton>
        </Stack>
    )
}